  ('heelevel3-1fb53453-moex-00294', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '下列每一種狀況都是單獨發生，且其他經濟條件沒有發生變化。假設用來生產碳粉匣的勞動市場 為充分就業。下列那一種狀況最可能導致該勞動市場中均衡的勞工就業量降低？', '["對影印機的需求增加", "生產碳粉匣的勞工非工資所得大幅提升", "婦女的勞動參與率普遍提高", "生產碳粉匣的勞工教育程度提高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00295', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', 'A、B兩國皆盛產鳳梨與香蕉兩種水果。下圖顯示兩國的生產可能線（productionpossibilitycurves）： 下列敘述何者正確？ 6', '["A國生產香蕉的機會成本是 單位的鳳梨 5", "A國在生產香蕉上有絕對利益（absoluteadvantage）", "A國應專業化生產鳳梨", "當貿易條件為1單位鳳梨換1單位香蕉時，兩國會在專業化後進行貿易"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00296', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '小芳只消費兩種財貨，衣服（x ）和食物（x ）。衣服和食物的價格分別為P 和P。下圖顯示她的', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00297', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '2 1 2 預算限制線與無異曲線。她的偏好符合單調性，即消費量越多，效用越高。她目前有所得200元。 圖中的A點代表一個可能的消費組合，（x x ）=（20,10）。 1, 2 下列敘述何者錯誤？', '["目前衣服的價格是8", "在A點，衣服對食物的邊際替代率絕對值大於2，因此她會想要少消費衣服，多消費食物", "就算衣服的價格下降，A點也不可能變成最適點", "在最適時小芳會把現有的200元所得花光"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00298', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '下列那一種情況是導致國內進口車市場均衡價格下降最合理的原因？', '["政府提高進口車的關稅", "蘇伊士運河堵塞導致部分進口車無法進入國內", "油價提高導致更多消費者寧可搭乘捷運", "消費者的所得提高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00299', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '經估計某A飲品的市場需求函數為： Q 15.40.5P 2P 2Y2D, A A B 其中Q 為消費者對A飲品的需求量，P 為其價格，P 為另一種飲品B的價格，Y為消費者所得 A A B 水準，D為虛擬變數（dummyvariable），其中D＝0為COVID-19疫情爆發前的時間，D＝1為疫 情爆發後的時間。所有係數在統計上均呈顯著。則下列敘述何者最為正確？', '["此時消費者對A飲品的價格需求彈性絕對值小於1", "飲品A與飲品B為替代品", "飲品A不會是奢侈品", "疫情將減少消費者對所有飲品的消費量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00300', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '如果煙霧偵測器的使用存在正的外部性，那麼當煙霧偵測器市場處於供需均衡狀態時：', '["煙霧偵測器的邊際社會利益超過邊際社會成本", "煙霧偵測器的邊際社會成本超過邊際社會利益", "煙霧偵測器的邊際社會成本等於邊際社會利益", "煙霧偵測器的實際銷售量超過了社會最適銷售量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00301', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '提供一個既定數量的擁擠性公共財（congestiblepublicgoods）給消費者時，每增加一位消費者的 邊際成本：', '["總是等於零", "為正且遞增", "為正且遞減", "一開始為零，但最後變為正且遞增"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('heelevel3-1fb53453-moex-00302', 'heelevel3-1fb53453', 'heelevel3-1fb53453-moex-110-51f0585d', 'sub-heelevel3-1fb53453-05', NULL, 'single_choice', '民主社會下的集體決策，下列敘述何者正確？', '["通常採多數決，因此符合柏拉圖效率（Paretoefficient）", "因為換票（logrolling）的存在，因此不具效率", "若所有人都具有單峰偏好（single-peakedpreference），決策將受中位數選舉人左右", "艾羅的不可能定理（Arrow’simpossibilitytheorem）不成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:29+00:00", "source_pdf_sha1": "45e44ddd5921", "answer_pdf_sha1": "4078ea2fe7aa", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "330", "s": "1010", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學概論與財政學概論", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財經廉政"}'::jsonb, NULL),
